import { ethers } from 'ethers';
import DechatRoomsABI from '../contracts/DechatRooms.json';
import DechatRoomsAddress from '../contracts/DechatRooms-address.json';

/**
 * Get contract instance with signer
 */
export const getContract = async () => {
  if (typeof window.ethereum === 'undefined') {
    throw new Error('MetaMask not installed');
  }

  const provider = new ethers.BrowserProvider(window.ethereum);
  const signer = await provider.getSigner();

  const contract = new ethers.Contract(
    DechatRoomsAddress.address,
    DechatRoomsABI.abi,
    signer
  );

  return contract;
};

/**
 * Get contract instance with provider (read-only)
 */
export const getContractReadOnly = async () => {
  if (typeof window.ethereum === 'undefined') {
    throw new Error('MetaMask not installed');
  }

  const provider = new ethers.BrowserProvider(window.ethereum);

  const contract = new ethers.Contract(
    DechatRoomsAddress.address,
    DechatRoomsABI.abi,
    provider
  );

  return contract;
};

/**
 * Create a new room
 */
export const createRoom = async (name, isNFTGated = false, nftContract = ethers.ZeroAddress) => {
  try {
    const contract = await getContract();
    const tx = await contract.createRoom(name, isNFTGated, nftContract);
    console.log('📤 Transaction sent:', tx.hash);
    
    const receipt = await tx.wait();
    console.log('✅ Transaction confirmed:', receipt.hash);
    
    // Extract roomId from event
    const event = receipt.logs.find(log => {
      try {
        const parsed = contract.interface.parseLog(log);
        return parsed.name === 'RoomCreated';
      } catch {
        return false;
      }
    });
    
    if (event) {
      const parsed = contract.interface.parseLog(event);
      return {
        success: true,
        roomId: parsed.args.roomId.toString(),
        txHash: receipt.hash
      };
    }
    
    return { success: true, txHash: receipt.hash };
  } catch (error) {
    console.error('Failed to create room:', error);
    throw error;
  }
};

/**
 * Join a room
 */
export const joinRoom = async (roomId) => {
  try {
    const contract = await getContract();
    const tx = await contract.joinRoom(roomId);
    console.log('📤 Transaction sent:', tx.hash);
    
    const receipt = await tx.wait();
    console.log('✅ Transaction confirmed:', receipt.hash);
    
    return { success: true, txHash: receipt.hash };
  } catch (error) {
    console.error('Failed to join room:', error);
    throw error;
  }
};

/**
 * Add message IPFS hash to room
 */
export const addMessageToRoom = async (contract, roomId, ipfsHash) => {
  try {
    const tx = await contract.addMessage(roomId, ipfsHash);
    console.log('📤 Message transaction sent:', tx.hash);
    
    const receipt = await tx.wait();
    console.log('✅ Message transaction confirmed:', receipt.hash);
    
    return { success: true, txHash: receipt.hash };
  } catch (error) {
    console.error('Failed to add message:', error);
    throw error;
  }
