/**
 * Get all messages for a room
 */
export const getRoomMessages = async (contract, roomId) => {
  try {
    const messages = await contract.getRoomMessages(roomId);
    return messages;
  } catch (error) {
    console.error('Failed to get room messages:', error);
    return [];
  }
